int solveQuery(int start, int end, std::vector<int>& arr) {
    std::unordered_map<int, int> mp;
    for (int i = start; i <= end; i++) {
        mp[arr[i]] = (mp.find(arr[i]) == mp.end()) ? 1 : mp[arr[i]] + 1;
    }
    int count = 0;
    for (auto& entry : mp) {
        if (entry.first == entry.second) {
            count++;
        }
    }
    return count;
}

