std::string decimalToBinary(double num, int k_prec) {
    std::string binary = "";
    int Integral = static_cast<int>(num);
    double fractional = num - Integral;
    while (Integral > 0) {
        int rem = Integral % 2;
        binary += static_cast<char>(rem + '0');
        Integral /= 2;
    }
    std::reverse(binary.begin(), binary.end());
    binary += '.';
    while (k_prec-- > 0) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= fract_bit;
            binary += static_cast<char>(1 + '0');
        } else {
            binary += static_cast<char>(0 + '0');
        }
    }
    return binary;
}

