        L[i][i] = 1;
    }
    for (cl = 2; cl <= n; cl++) {
        for (i = 0; i < n - cl + 1; i++) {
            j = i + cl - 1;
            if (seq[i] == seq[j] && cl == 2) {
                L[i][j] = 2;
