    for (int i = 0; i < n; i++) {
        F[i][i] = (symb[i] == 'F') ? 1 : 0;
        T[i][i] = (symb[i] == 'T') ? 1 : 0;
    }
    for (int gap = 1; gap < n; ++gap) {
        for (int i = 0, j = gap; j < n; ++i, ++j) {
            T[i][j] = F[i][j] = 0;
            for (int g = 0; g < gap; g++) {
                int k = i + g;
                int tik = T[i][k] + F[i][k];
