bool findDuplicateparenthesis(std::string s) {
  std::stack<char> Stack;
  for (char ch : s) {
    if (ch == ')') {
      char top = Stack.top();
      Stack.pop();
      int elementsInside = 0;
      while (top != '(') {
        elementsInside++;
        top = Stack.top();
        Stack.pop();
      }
      if (elementsInside < 1) {
        return true;
      }
    } else {
      Stack.push(ch);
    }
  }
  return false;
}

