struct Indexes {
    int i, j;
    Indexes(int i, int j) : i(i), j(j) {}
    int getI() { return i; }
    int getJ() { return j; }
};
int findFourElements(int arr[], int n) {
    std::unordered_map<int, Indexes> map;
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            map[arr[i] + arr[j]] = Indexes(i, j);
        }
    }
    int d = INT_MIN;
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            int abs_diff = std::abs(arr[i] - arr[j]);
            if (map.find(abs_diff) != map.end()) {
                Indexes indexes = map[abs_diff];
                if (indexes.getI() != i && indexes.getI() != j && indexes.getJ() != i && indexes.getJ() != j) {
                    d = std::max(d, std::max(arr[i], arr[j]));
                }
            }
        }
    }
    return d;
}

