int maxRevenue(int m, int x[], int revenue[], int n, int t) {
    int maxRev[m + 1];
    for (int i = 0; i < m + 1; i++) {
        maxRev[i] = 0;
    }
    int nxtbb = 0;
    for (int i = 1; i <= m; i++) {
        if (nxtbb < n) {
            if (x[nxtbb] != i) {
                maxRev[i] = maxRev[i - 1];
            } else {
                if (i <= t) {
                    maxRev[i] = std::max(maxRev[i - 1], revenue[nxtbb]);
                } else {
                    maxRev[i] = std::max(maxRev[i - t - 1] + revenue[nxtbb], maxRev[i - 1]);
                }
                nxtbb++;
            }
        } else {
            maxRev[i] = maxRev[i - 1];
        }
    }
    return maxRev[m];
}

