            dp[i][i + 1] = 2;
        }
    }
    for (int l = 2; l < n; l++) {
        for (int i = 0, j = l; j < n; i++, j++) {
            if (s[i] == '(' && s[j] == ')') {
                dp[i][j] = 2 + dp[i + 1][j - 1];
