void minimizeWithKSwaps(int arr[], int n, int k) {
    for (int i = 0; i < n - 1 && k > 0; ++i) {
        int pos = i;
        for (int j = i + 1; j < n; ++j) {
            if (j - i > k) break;
            if (arr[j] < arr[pos]) pos = j;
