        factorCount[i] = 0;
        prime[i] = true;
    }
    for (int i = 2; i <= n; i++) {
        if (prime[i] == true) {
            factorCount[i] = 1;
            for (int j = i * 2; j <= n; j += i) {
                factorCount[j]++;
                prime[j] = false;
            }
