    int max = static_cast<int>(factorCount[m]);
    int num = m;
    for (int i = m; i <= n; i++) {
        if (factorCount[i] > max) {
            max = static_cast<int>(factorCount[i]);
            num = i;
        }
    }
    return num;
}

