    }
    for (int i = 0; i < n; i++) {
        int wstIdx = -1;
        for (int j = 0; j < m; j++) {
            if (blockSize[j] >= processSize[i]) {
                if (wstIdx == -1) {
                    wstIdx = j;
                } else if (blockSize[wstIdx] < blockSize[j]) {
                    wstIdx = j;
                }
            }
