int sumoflength(int arr[], int n) {
    std::vector<int> s;
    int j = 0;
    int ans = 0;
    for (int i = 0; i < n; i++) {
        std::unordered_set<int> set(s.begin(), s.end());
        while (j < n && set.find(arr[j]) == set.end()) {
            s.push_back(arr[j]);
