int offeringNumber(int n, int templeHeight[]) {
    int sum = 0;
    for (int i = 0; i < n; ++i) {
        int left = 0, right = 0;
        for (int j = i - 1; j >= 0; --j) {
            if (templeHeight[j] < templeHeight[j + 1]) ++left;
            else break;
        }
        for (int j = i + 1; j < n; ++j) {
            if (templeHeight[j] < templeHeight[j - 1]) ++right;
            else break;
        }
        sum += std::max(right, left) + 1;
    }
    return sum;
}

